  export const covers = (props: {
    components: OpenApi.IComponents;
    x: OpenApi.IJsonSchema;
    y: OpenApi.IJsonSchema;
  }): boolean =>
    OpenApiTypeCheckerBase.covers({
      prefix: "#/components/schemas/",
